defmodule MyAppWeb.ProductController do
  use MyAppWeb, :controller

  alias MyApp.Repo
  alias MyApp.Product # Assuming MyApp.Product is your Ecto schema for products

  def index(conn, params) do
    search_term = Map.get(params, "search", "")

    products =
      if search_term != "" do
        Repo.all(
          from p in Product,
            where: fragment("name LIKE '%#{^search_term}%'")
        )
      else
        # If no search term, return all products or an empty list, depending on desired behavior
        Repo.all(Product)
      end

    # For an API, typically render JSON
    conn
    |> put_status(:ok)
    |> render("index.json", products: products)
  end
end